{
  "title": "जमीनबाज़ी बनाम घुमंतुकरण",
  "group": "उन्नत",
  "options": [
    {
      "text": "मॉडल को सिस्टम प्रॉम्प्ट में \"घुमंतुकरण न करें\" बताएं"
    },
    {
      "text": "अधिक तापमान का उपयोग करें ताकि अधिक आत्मविश्वासपूर्ण प्रतिक्रिया हो"
    },
    {
      "text": "पुनर्प्राप्त स्रोत दस्तावेज़ प्रदान करें और मॉडल को उन्हें संदर्भित करने के लिए निर्देश दें"
    },
    {
      "text": "एक बड़ा मॉडल उपयोग करें — घुमंतुकरण केवल छोटे मॉडल में होता है"
    }
  ],
  "questionProse": [
    "एक उत्पादन एआई प्रणाली में घुमंतुकरण को कम करने का सबसे प्रभावी तकनीक है:"
  ],
  "explanationProse": [
    "मॉडल को घुमंतुकरण न करने के लिए निर्देश देने से घुमंतुकरण रुकता नहीं है — मॉडल के पास \"मैं झूठ बोल रहा हूँ\" के लिए एक विश्वसनीय आंतरिक संकेत नहीं होता है। यह बस मॉडल को बताएगा कि वह झूठ बोल रहा है जबकि वास्तव में झूठ बोल रहा है।\n\n    जो काम करता है: **जमीनबाज़ी**। मॉडल को सही जवाब देने के लिए आवश्यक जानकारी प्रदान करें और उसे उस जानकारी पर रोके:",
    "फिर आउटपुट का सत्यापन करें: प्रतिक्रिया में क्लेम की पुनर्प्राप्त संदर्भ में उपस्थिति की जाँच करें। यह संदर्भ जमीनबाज़ी जाँच है — RAG आकलन चर्चा देखें इम्प्लीमेंटेशन के लिए।\n\n    बड़े मॉडल औसतन कम घुमंतुकरण करते हैं, लेकिन सभी मॉडल घुमंतुकरण करते हैं। जमीनबाज़ी तकनीकी है, मॉडल आकार नहीं।"
  ]
}
